import{_ as o,o as u,c as q,a2 as r}from"./chunks/framework.BbQrW5_t.js";const h=JSON.parse('{"title":"《干法》读书笔记","description":"","frontmatter":{"title":"《干法》读书笔记","date":"2026-07-13T00:00:00.000Z","tags":["读书笔记","职场发展","稻盛和夫","工作哲学","人生经营"],"category":"职场发展"},"headers":[],"relativePath":"study/reading-notes/20260713-《干法》读书笔记.md","filePath":"study/reading-notes/20260713-《干法》读书笔记.md","lastUpdated":1783931283000}'),l={name:"study/reading-notes/20260713-《干法》读书笔记.md"};function a(e,t,n,i,s,d){return u(),q("div",null,[...t[0]||(t[0]=[r('<h1 id="《干法》读书笔记" tabindex="-1">《干法》读书笔记 <a class="header-anchor" href="#《干法》读书笔记" aria-label="Permalink to &quot;《干法》读书笔记&quot;">​</a></h1><blockquote><p>作者：[日] 稻盛和夫 | 译者：曹岫云 | 出版：华文出版社，2010年5月 阅读时间：2026-07-13</p></blockquote><hr><h2 id="📌-一、核心观点" tabindex="-1">📌 一、核心观点 <a class="header-anchor" href="#📌-一、核心观点" aria-label="Permalink to &quot;📌 一、核心观点&quot;">​</a></h2><h3 id="本书讲了什么" tabindex="-1">本书讲了什么 <a class="header-anchor" href="#本书讲了什么" aria-label="Permalink to &quot;本书讲了什么&quot;">​</a></h3><p>本书是&quot;日本经营之圣&quot;稻盛和夫关于&quot;工作&quot;的哲学思考，是《活法》的姊妹篇。核心主题：<strong>工作的真正意义是什么？如何通过工作磨炼灵魂、提升心志，获得幸福的人生？</strong></p><p>稻盛和夫27岁创业，40年间创建京瓷和KDDI两家&quot;世界500强&quot;企业，78岁出任破产重建的日航CEO并成功扭亏为盈。他将自己一生的实践经验提炼为&quot;劳动观&quot;和&quot;工作观&quot;。</p><h3 id="核心论点" tabindex="-1">核心论点 <a class="header-anchor" href="#核心论点" aria-label="Permalink to &quot;核心论点&quot;">​</a></h3><p><strong>1. 工作的本质意义——磨炼灵魂、提升心志 🔴🔴🔴</strong></p><blockquote><p>&quot;工作是人生最尊贵、最重要、最有价值的行为。&quot;</p></blockquote><p>大多数人认为工作只是为了吃饭获取报酬，是&quot;必要之恶&quot;。稻盛和夫认为，工作的真正目的是<strong>提升心志、磨炼人格</strong>。日复一日勤奋工作，可以起到锻炼心志、提升人性的了不起作用。</p><p><strong>2. 改变心态——让自己喜欢上工作 🔴🔴🔴</strong></p><blockquote><p>&quot;要想度过一个充实的人生，只有两种选择：一种是&#39;从事自己喜欢的工作&#39;，另一种是&#39;让自己喜欢上工作&#39;。&quot;</p></blockquote><p>能够碰上自己喜欢的工作的几率不足千分之一。与其寻找自己喜欢的工作，不如先喜欢上已有的工作。从&quot;厌恶工作&quot;转变为&quot;迷恋工作&quot;，就能进入良性循环：喜欢→投入→成果→肯定→更喜欢。</p><p><strong>3. 付出&quot;不亚于任何人的努力&quot; 🔴🔴🔴</strong></p><blockquote><p>&quot;平平常常的努力，不管是企业还是个人，都不可能获得理想的成果。&quot;</p></blockquote><p>这不是普通的努力，而是<strong>无限度的、永无止境的努力</strong>。用百米赛的速度跑马拉松——这是京瓷从后进者变成领先者的秘诀。自然界的一切生物都在拼命努力求生，人类追求安乐反而是违背自然机理的。</p><p><strong>4. 持续的力量——将&quot;平凡&quot;变为&quot;非凡&quot; 🔴🔴</strong></p><blockquote><p>&quot;伟大的事业乃是朴实、枯燥工作的积累。&quot;</p></blockquote><p>金字塔是由无数无名氏一块一块砌上去的。专心致志于一行一业，不腻烦、不焦躁，埋头苦干，就能让&quot;平凡的人&quot;变成&quot;非凡的人&quot;。那些看起来不起眼、只是踏踏实实工作的人，往往能成为优秀的领导者。</p><p><strong>5. 追求&quot;完美主义&quot;——不是&quot;最佳&quot;，而是&quot;完美&quot; 🔴🔴</strong></p><blockquote><p>&quot;要完成一个产品，99%的努力是不够的。一点差错、一点疏忽、一点马虎都不能允许。&quot;</p></blockquote><p>&quot;最佳&quot;是相对的，是同别人比较。&quot;完美&quot;是绝对的，是自身具备可靠的价值。成败取决于&quot;最后1%的努力&quot;，懈怠最后1%，前面的努力全都前功尽弃。</p><p><strong>6. 创造性地工作——走别人没走过的路 🔴🔴</strong></p><blockquote><p>&quot;铺装平整的大道是大家都想走的路。若只知步别人的后尘，则绝不能开拓新的事业。&quot;</p></blockquote><p>每天都要钻研创新，即使一天的进步微不足道，但若经过十年的积累，就能孕育巨大的变化。外行的长处是可以&quot;自由发想&quot;，不被成见束缚。</p><p><strong>7. 人生方程式——思维方式×热情×能力 🔴🔴🔴</strong></p><blockquote><p>人生·工作的结果 = 思维方式 × 热情 × 能力</p></blockquote><p>这是稻盛和夫最核心的公式：</p><ul><li><strong>能力</strong>：天赋资质，0-100分（先天）</li><li><strong>热情</strong>：努力程度，0-100分（后天可控）</li><li><strong>思维方式</strong>：态度和价值观，-100到100分（最关键）</li></ul><p>乘法运算意味着：如果思维方式是负值，能力越强、热情越高，结果反而越糟糕。正确的思维方式包括：积极向上、诚实正直、谦虚谨慎、勤奋努力、不自私、有感恩心等。</p><h3 id="关键框架" tabindex="-1">关键框架 <a class="header-anchor" href="#关键框架" aria-label="Permalink to &quot;关键框架&quot;">​</a></h3><table tabindex="0"><thead><tr><th>框架</th><th>核心内容</th></tr></thead><tbody><tr><td><strong>工作意义</strong></td><td>磨炼灵魂、提升心志，而非仅仅谋生</td></tr><tr><td><strong>心态转变</strong></td><td>从&quot;厌恶&quot;到&quot;迷恋&quot;，创造良性循环</td></tr><tr><td><strong>努力程度</strong></td><td>不亚于任何人，用百米速度跑马拉松</td></tr><tr><td><strong>持续积累</strong></td><td>每天进步一点，十年积累成巨大变化</td></tr><tr><td><strong>完美主义</strong></td><td>不是&quot;最佳&quot;（相对），而是&quot;完美&quot;（绝对）</td></tr><tr><td><strong>创新精神</strong></td><td>走别人没走过的路，每天钻研创新</td></tr><tr><td><strong>人生方程式</strong></td><td>思维方式×热情×能力，思维方式最关键</td></tr></tbody></table><hr><h2 id="💡-二、启发思考" tabindex="-1">💡 二、启发思考 <a class="header-anchor" href="#💡-二、启发思考" aria-label="Permalink to &quot;💡 二、启发思考&quot;">​</a></h2><h3 id="对一般人的启发" tabindex="-1">对一般人的启发 <a class="header-anchor" href="#对一般人的启发" aria-label="Permalink to &quot;对一般人的启发&quot;">​</a></h3><ol><li><strong>重新定义&quot;工作&quot;</strong>——工作不是为了谋生，而是人生修行的道场</li><li><strong>&quot;天职&quot;是自己创造的</strong>——不是碰上喜欢的才努力，而是努力了才会喜欢</li><li><strong>努力可以弥补天赋不足</strong>——60分能力×90分努力 &gt; 90分能力×30分努力</li><li><strong>持续比爆发更重要</strong>——金字塔是一块石头一块石头堆起来的</li><li><strong>思维方式决定人生走向</strong>——负面的思维方式会让一切努力走向反面</li></ol><h3 id="从心理学和实践角度的启发-🎯" tabindex="-1">从心理学和实践角度的启发 🎯 <a class="header-anchor" href="#从心理学和实践角度的启发-🎯" aria-label="Permalink to &quot;从心理学和实践角度的启发 🎯&quot;">​</a></h3><h4 id="🌱-人生发展维度" tabindex="-1">🌱 人生发展维度 <a class="header-anchor" href="#🌱-人生发展维度" aria-label="Permalink to &quot;🌱 人生发展维度&quot;">​</a></h4><ol><li><p><strong>&quot;必要之恶&quot;观念的心理根源</strong>：稻盛和夫指出，西方基督教文化将劳动视为对原罪的惩罚，这种观念深刻影响了现代人的工作观。而日本传统文化认为劳动能带来喜悦和自豪——这种文化差异提醒我们：<strong>观念决定体验</strong>，改变对工作的认知，就能改变工作的感受</p></li><li><p><strong>&quot;自燃型&quot;人格的心理特质</strong>：稻盛和夫将人分为&quot;可燃型&quot;、&quot;不燃型&quot;和&quot;自燃型&quot;。心理学研究表明，&quot;自燃型&quot;对应的是<strong>内在动机驱动</strong>——不是为了外部奖励而工作，而是因为工作本身有意义。17年技术开发和管理，我的工作动力是否已经从&quot;内在动机&quot;转向了&quot;外部压力&quot;？</p></li><li><p><strong>苦难的意义重构</strong>：稻盛和夫年轻时连续遭遇挫折，但他认为&quot;乍看的不幸，实际上是幸事&quot;。心理学中的<strong>创伤后成长</strong>（Post-traumatic Growth）理论证实：适度苦难可以促进人格成熟。我目前的&quot;精力下降&quot;和&quot;转型困境&quot;是否也可以被重新定义为成长的契机？</p></li></ol><h4 id="🏠-家庭关系维度" tabindex="-1">🏠 家庭关系维度 <a class="header-anchor" href="#🏠-家庭关系维度" aria-label="Permalink to &quot;🏠 家庭关系维度&quot;">​</a></h4><ol><li><p><strong>工作态度的家庭传承</strong>：稻盛和夫说&quot;工作造就人格&quot;。作为两个孩子的父亲，我对待工作的态度会直接影响孩子对&quot;努力&quot;的认知。如果我在工作中表现出抱怨和逃避，孩子学到的是&quot;工作很苦&quot;；如果表现出投入和热爱，孩子学到的是&quot;努力有意义&quot;</p></li><li><p><strong>家庭决策的&quot;思维方式&quot;</strong>：稻盛和夫强调思维方式是最关键的乘数。在家庭重大决策中（如转型方向、教育投资、财务规划），负面的思维方式（抱怨、焦虑、自我否定）会让决策质量大幅下降</p></li><li><p><strong>感谢之心对家庭氛围的影响</strong>：稻盛和夫反复强调&quot;感谢&quot;的重要性。心理学研究表明，感恩练习可以显著提升家庭幸福感。每天表达感谢，可以改善夫妻关系、亲子关系</p></li></ol><h4 id="💼-事业发展维度" tabindex="-1">💼 事业发展维度 <a class="header-anchor" href="#💼-事业发展维度" aria-label="Permalink to &quot;💼 事业发展维度&quot;">​</a></h4><ol><li><p><strong>&quot;付出不亚于任何人的努力&quot;的现实意义</strong>：稻盛和夫用百米赛的速度跑马拉松的比喻，让我反思：17年的技术管理经验积累，是否已经让我进入了&quot;舒适区&quot;？当精力下降时，我是选择降低努力程度，还是寻找新的努力方向？</p></li><li><p><strong>&quot;能力要用将来进行时&quot;的转型启示</strong>：稻盛和夫主张设定超过现有能力的目标，然后想办法提高能力来达成。转型过程中，我常常说&quot;我没有那个行业的能力&quot;——但这恰恰是&quot;现有能力&quot;思维，而非&quot;将来进行时&quot;思维</p></li><li><p><strong>&quot;持续就是力量&quot;的深意</strong>：京瓷从一个只有28人的小公司成长为世界500强，靠的是持续的努力而非一时的爆发。转型也需要这样的思维——不是寻求&quot;快速成功&quot;，而是接受&quot;长期积累&quot;的过程</p></li></ol><h4 id="📚-小孩子教育维度" tabindex="-1">📚 小孩子教育维度 <a class="header-anchor" href="#📚-小孩子教育维度" aria-label="Permalink to &quot;📚 小孩子教育维度&quot;">​</a></h4><ol><li><p><strong>努力观的传承</strong>：稻盛和夫认为&quot;付出不亚于任何人的努力&quot;是做人最基本的条件。这种观念可以教给孩子：努力不是痛苦，而是成长的必经之路</p></li><li><p><strong>&quot;完美主义&quot;的教育意义</strong>：稻盛和夫追求的不是&quot;差不多就行&quot;，而是&quot;完美&quot;。这可以转化为对孩子的教育：学习不是为了完成作业，而是为了真正掌握知识；做事不是为了敷衍，而是为了做到最好</p></li><li><p><strong>人生方程式的启蒙</strong>：思维方式×热情×能力的公式可以简化给孩子：聪明不等于成功，努力很重要，但态度最关键。一个诚实、善良、积极的孩子，即使天赋普通，人生也会很美好</p></li></ol><hr><h2 id="🎯-三、以我的背景给的建议" tabindex="-1">🎯 三、以我的背景给的建议 <a class="header-anchor" href="#🎯-三、以我的背景给的建议" aria-label="Permalink to &quot;🎯 三、以我的背景给的建议&quot;">​</a></h2><h3 id="背景-17年开发-技术管理-两个孩子父亲-精力下降想转型" tabindex="-1">背景：17年开发+技术管理，两个孩子父亲，精力下降想转型 <a class="header-anchor" href="#背景-17年开发-技术管理-两个孩子父亲-精力下降想转型" aria-label="Permalink to &quot;背景：17年开发+技术管理，两个孩子父亲，精力下降想转型&quot;">​</a></h3><h4 id="🌱-人生发展建议" tabindex="-1">🌱 人生发展建议 <a class="header-anchor" href="#🌱-人生发展建议" aria-label="Permalink to &quot;🌱 人生发展建议&quot;">​</a></h4><p><strong>建议一：重新定义&quot;转型&quot;的意义 🔴🔴🔴</strong></p><p>稻盛和夫说工作是为了&quot;磨炼灵魂、提升心志&quot;。转型不是逃避工作，而是寻找新的&quot;修行道场&quot;。</p><p>心理学上的&quot;意义疗法&quot;（维克多·弗兰克尔）表明：当人们找到苦难的意义时，就能承受任何苦难。将转型定义为：</p><ul><li>不是&quot;逃离疲惫的技术工作&quot;</li><li>而是&quot;寻找新的成长方式和人格修炼场&quot;</li></ul><p><strong>建议二：检查&quot;思维方式&quot;是否转向负面 🔴🔴🔴</strong></p><p>稻盛和夫的人生方程式中，思维方式是-100到100分。如果思维方式变成负值，能力再强也会失败。</p><p>常见的负面思维方式对照表：</p><table tabindex="0"><thead><tr><th>负面思维方式</th><th>具体表现</th><th>转化为正面</th></tr></thead><tbody><tr><td>抱怨现有工作</td><td>&quot;技术工作太累&quot;</td><td>&quot;这是我磨炼心志的机会&quot;</td></tr><tr><td>焦虑未来</td><td>&quot;转型失败怎么办&quot;</td><td>&quot;先全力以赴，失败也是成长&quot;</td></tr><tr><td>自我否定</td><td>&quot;我没有其他能力&quot;</td><td>&quot;我可以学习新能力&quot;</td></tr><tr><td>嫉妒他人</td><td>&quot;别人转型成功了&quot;</td><td>&quot;我要向成功者学习&quot;</td></tr></tbody></table><p><strong>建议三：从&quot;不燃型&quot;转向&quot;自燃型&quot; 🔴🔴</strong></p><p>稻盛和夫将人分为三种类型。作为管理者，我可能已经习惯了&quot;等待命令&quot;的模式。</p><p>自燃型的特征：</p><ul><li>不等别人吩咐就主动行动</li><li>有明确的目标和问题意识</li><li>进入&quot;旋涡中心&quot;，带动周围的人</li></ul><p>转型需要这种自燃型精神：不是等待机会，而是主动创造机会；不是被动适应，而是积极开拓。</p><h4 id="🏠-家庭关系建议" tabindex="-1">🏠 家庭关系建议 <a class="header-anchor" href="#🏠-家庭关系建议" aria-label="Permalink to &quot;🏠 家庭关系建议&quot;">​</a></h4><p><strong>建议四：让家人理解你的&quot;工作哲学&quot; 🔴🔴</strong></p><p>稻盛和夫说&quot;工作造就人格&quot;。和家人分享这本书的核心观点：</p><ul><li>努力工作不是为了牺牲家庭，而是为了成为更好的自己</li><li>一个有追求的父亲，本身就是对孩子最好的教育</li></ul><p>这种沟通可以减少家人的担忧，让转型成为全家共同的目标而非个人的冒险。</p><p><strong>建议五：建立家庭&quot;感谢仪式&quot; 🔴</strong></p><p>稻盛和夫反复强调感谢的重要性。建议：</p><ul><li>每天晚餐时，每个人说一件今天值得感谢的事</li><li>周末时，向家人表达对本周努力的感谢</li></ul><p>心理学研究表明，这种简单的练习可以显著提升家庭幸福感。</p><h4 id="💼-事业发展建议" tabindex="-1">💼 事业发展建议 <a class="header-anchor" href="#💼-事业发展建议" aria-label="Permalink to &quot;💼 事业发展建议&quot;">​</a></h4><p><strong>建议六：用&quot;能力将来进行时&quot;思维规划转型 🔴🔴🔴</strong></p><p>稻盛和夫主张：设定超过现有能力的目标，然后想办法提高能力来达成。</p><p>具体做法：</p><table tabindex="0"><thead><tr><th>现有思维</th><th>将来进行时思维</th></tr></thead><tbody><tr><td>&quot;我没有运营经验&quot;</td><td>&quot;我可以在6个月内学习运营基础&quot;</td></tr><tr><td>&quot;我没有行业人脉&quot;</td><td>&quot;我可以通过参加行业活动建立人脉&quot;</td></tr><tr><td>&quot;我精力下降&quot;</td><td>&quot;我可以调整工作方式，用智慧而非体力&quot;</td></tr></tbody></table><p><strong>建议七：接受&quot;持续积累&quot;的转型节奏 🔴🔴</strong></p><p>稻盛和夫用金字塔比喻：伟大事业是无数块石头积累起来的。转型不是&quot;快速成功&quot;，而是：</p><ul><li>每天学习一点新领域知识</li><li>每周尝试一点新方向</li><li>每月完成一个小目标</li><li>一年积累成可观的成果</li></ul><p>这符合心理学中的<strong>渐进改变理论</strong>——大目标分解为小步骤，更容易坚持。</p><p><strong>建议八：从&quot;最佳&quot;转向&quot;完美&quot; 🔴</strong></p><p>稻盛和夫区分&quot;最佳&quot;（相对）和&quot;完美&quot;（绝对）。在技术管理中，我们习惯了&quot;比别人好就行&quot;的思维。转型时，应该追求：</p><ul><li>不是&quot;比其他转型者成功&quot;</li><li>而是&quot;在自己的领域做到无可挑剔&quot;</li></ul><p>这种思维转变可以减少攀比焦虑，专注于自己的成长。</p><h4 id="📚-小孩子教育建议" tabindex="-1">📚 小孩子教育建议 <a class="header-anchor" href="#📚-小孩子教育建议" aria-label="Permalink to &quot;📚 小孩子教育建议&quot;">​</a></h4><p><strong>建议九：用&quot;人生方程式&quot;教育孩子 🔴🔴</strong></p><p>简化稻盛和夫的公式给孩子：</p><p><strong>成功 = 态度 × 努力 × 天赋</strong></p><p>告诉孩子：</p><ul><li>天赋是上天给的，不必比较</li><li>努力是自己决定的，越努力越好</li><li><strong>态度最重要</strong>——诚实、善良、积极，比聪明更重要</li></ul><p><strong>建议十：培养&quot;自燃型&quot;品格 🔴</strong></p><p>教孩子成为自燃型的人：</p><ul><li>不等父母催促就主动学习</li><li>遇到问题先自己想办法</li><li>不抱怨作业多，而是想办法高效完成</li></ul><p>这比教孩子具体知识更重要——因为品格决定一生的走向。</p><p><strong>建议十一：用工作态度做示范 🔴🔴</strong></p><p>稻盛和夫说&quot;工作造就人格&quot;。孩子在观察父亲：</p><ul><li>如果父亲在工作中表现出热爱和投入，孩子学到的是&quot;努力有意义&quot;</li><li>如果父亲表现出抱怨和逃避，孩子学到的是&quot;工作很苦&quot;</li></ul><p>转型过程中，保持积极的态度本身就是对孩子最好的教育。</p><hr><h2 id="📋-四、行动计划" tabindex="-1">📋 四、行动计划 <a class="header-anchor" href="#📋-四、行动计划" aria-label="Permalink to &quot;📋 四、行动计划&quot;">​</a></h2><h3 id="短期-1-3个月" tabindex="-1">短期（1-3个月） <a class="header-anchor" href="#短期-1-3个月" aria-label="Permalink to &quot;短期（1-3个月）&quot;">​</a></h3><ul><li>[ ] <strong>思维方式体检</strong>：对照负面思维方式清单，检查自己是否有抱怨、焦虑、自我否定等倾向</li><li>[ ] <strong>建立每日反省习惯</strong>：稻盛和夫每晚反省自己的过失——开始写&quot;每日三省&quot;日记</li><li>[ ] <strong>重新定义转型目标</strong>：将&quot;逃离技术工作&quot;转变为&quot;寻找新的成长道场&quot;</li><li>[ ] <strong>学习&quot;将来进行时&quot;思维</strong>：对每个&quot;我不会&quot;的想法，后面加上&quot;但我可以学习&quot;</li><li>[ ] <strong>和家人分享工作哲学</strong>：用稻盛和夫的观点，让家人理解努力工作的正面意义</li></ul><h3 id="中期-3-6个月" tabindex="-1">中期（3-6个月） <a class="header-anchor" href="#中期-3-6个月" aria-label="Permalink to &quot;中期（3-6个月）&quot;">​</a></h3><ul><li>[ ] <strong>每天付出&quot;不亚于任何人的努力&quot;</strong>：不是降低标准，而是找到新的努力方式</li><li>[ ] <strong>建立家庭感谢仪式</strong>：每天晚餐时表达感谢，改善家庭氛围</li><li>[ ] <strong>分解转型目标</strong>：将大目标分解为每月的小目标，持续积累</li><li>[ ] <strong>成为&quot;自燃型&quot;管理者</strong>：不等上级指示就主动发现问题、解决问题</li><li>[ ] <strong>阅读稻盛和夫其他著作</strong>：《活法》《心》《稻盛和夫的实学》等，建立完整的思想体系</li></ul><h3 id="长期-6-24个月" tabindex="-1">长期（6-24个月） <a class="header-anchor" href="#长期-6-24个月" aria-label="Permalink to &quot;长期（6-24个月）&quot;">​</a></h3><ul><li>[ ] <strong>形成个人的&quot;工作哲学&quot;</strong>：将稻盛和夫的思想与自己的实践结合，形成自己的工作观</li><li>[ ] <strong>用&quot;完美主义&quot;精神完成转型</strong>：不是&quot;差不多就行&quot;，而是做到无可挑剔</li><li>[ ] <strong>成为转型领域的&quot;自燃型&quot;领导者</strong>：带动周围的人一起成长</li><li>[ ] <strong>教导孩子人生方程式</strong>：态度×努力×天赋，态度最重要</li><li>[ ] <strong>持续积累新领域的知识和经验</strong>：像砌金字塔一样，一块石头一块石头往上堆</li></ul><hr><h2 id="📖-精彩摘录" tabindex="-1">📖 精彩摘录 <a class="header-anchor" href="#📖-精彩摘录" aria-label="Permalink to &quot;📖 精彩摘录&quot;">​</a></h2><blockquote><p>&quot;工作是人生最尊贵、最重要、最有价值的行为。&quot;</p></blockquote><blockquote><p>&quot;要想度过一个充实的人生，只有两种选择：一种是&#39;从事自己喜欢的工作&#39;，另一种是&#39;让自己喜欢上工作&#39;。能够碰上自己喜欢的工作的几率，恐怕不足千分之一。&quot;</p></blockquote><blockquote><p>&quot;付出不亚于任何人的努力——这不是普通的努力，而是无限度的、永无止境的努力。&quot;</p></blockquote><blockquote><p>&quot;持续的力量能将&#39;平凡&#39;变为&#39;非凡&#39;。金字塔是由许许多多无名氏，通过艰苦的地道作业堆砌而成的。&quot;</p></blockquote><blockquote><p>&quot;要完成一个产品，99%的努力是不够的。一点差错、一点疏忽、一点马虎都不能允许。&quot;</p></blockquote><blockquote><p>&quot;不是&#39;最佳&#39;而是&#39;完美&#39;。&#39;最佳&#39;是同别人比较，是相对的；&#39;完美&#39;是绝对的，自身具备可靠的价值。&quot;</p></blockquote><blockquote><p>&quot;人生·工作的结果 = 思维方式 × 热情 × 能力。思维方式最重要，因为它是-100到100分。&quot;</p></blockquote><blockquote><p>&quot;冬天越寒冷，樱花就开得越烂漫。人也是一样，不体验痛苦和烦恼，就很难有大的发展。&quot;</p></blockquote><blockquote><p>&quot;已经不行了的时候，才是真正的开始。&quot;</p></blockquote><blockquote><p>&quot;能力要用将来进行时——设定超过现有能力的目标，然后想办法提高能力来达成。&quot;</p></blockquote><blockquote><p>&quot;外行的长处是可以自由发想——不被成见束缚，敢于挑战新事物。&quot;</p></blockquote><blockquote><p>&quot;每天一点的钻研创新，日积月累，就能孕育真正的创造和成功。&quot;</p></blockquote><hr><h2 id="🔗-相关书籍推荐" tabindex="-1">🔗 相关书籍推荐 <a class="header-anchor" href="#🔗-相关书籍推荐" aria-label="Permalink to &quot;🔗 相关书籍推荐&quot;">​</a></h2><table tabindex="0"><thead><tr><th>书名</th><th>关系</th><th>推荐理由</th></tr></thead><tbody><tr><td>《活法》</td><td>姊妹篇</td><td>稻盛和夫的人生哲学，与《干法》构成完整体系</td></tr><tr><td>《心》</td><td>深入版</td><td>稻盛和夫晚年思想精华，更深入的哲学思考</td></tr><tr><td>《稻盛和夫的实学》</td><td>实践版</td><td>经营哲学的具体实践方法</td></tr><tr><td>《卓有成效的管理者》</td><td>互补</td><td>德鲁克的管理思想，与稻盛哲学互补</td></tr><tr><td>《原则》</td><td>互补</td><td>达利欧的生活和工作原则，现代版的哲学思考</td></tr></tbody></table>',124)])])}const g=o(l,[["render",a]]);export{h as __pageData,g as default};
